"""Abstract base class for dataset format normalizers."""

from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Any, Dict, Iterator, List


class Format(ABC):
    """Base class for dataset format normalizers.

    Subclasses must implement ``normalize()`` to yield column-oriented
    batches (``dict[str, list]``).  Override ``schema()`` and
    ``pg_schema()`` to declare type hints and PostgreSQL domain types.
    """

    @abstractmethod
    def normalize(self) -> Iterator[Dict[str, List[Any]]]:
        """Yield column-oriented batches: ``{col_name: [values...]}``.

        Each batch is a dict mapping column names to equal-length lists
        (one entry per row).
        """
        ...

    def schema(self) -> Dict[str, str]:
        """Return ``{col: deeplake_type}`` hints.

        Override to declare types for columns where inference from Python
        values is ambiguous (e.g. ``bytes`` could be ``BINARY``,
        ``IMAGE``, ``SEGMENT_MASK``, etc.).
        """
        return {}

    def pg_schema(self) -> Dict[str, str]:
        """Return ``{col: pg_domain_type}`` overrides.

        Override to apply pg_deeplake domain types (e.g. ``IMAGE``,
        ``SEGMENT_MASK``, ``VIDEO``) after table creation.
        """
        return {}

    def image_columns(self) -> List[str]:
        """Return column names containing IMAGE data (for thumbnail generation).

        Default: auto-detect from ``pg_schema()`` — columns with type
        ``"IMAGE"``.  Override to customize.
        """
        return [col for col, t in self.pg_schema().items() if t == "IMAGE"]
